var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"예? 델타세븐이라면......","JPN":"はい？　デルタセブンなら……","ENG":"Pardon? Delta Seven is...","TWN":"嗯？第七三角洲部隊……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"그래, 네가 존경해 마지 않는 마리아 안토노프 사령관님께서 지휘하는 부대다.","JPN":"そうだ、君が尊敬してやまないマリア・アントノフ司令官が率いる部隊だ。","ENG":"That's right. It's the unit under the command of your favorite Maria Antonov.","TWN":"沒錯，就是你無比尊敬的那位瑪麗亞·安東諾夫司令官所指揮的部隊。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"화려한 근접 전투 시연을 하라고 보내놨더니 20초 만에 행사를 끝내버려서 한 소리 듣겠다 싶었는데......","JPN":"華やかな近接戦闘試演を披露するようと言ったはずだが、たった20秒でイベントを終わらせてしまい、\\n詰問されるんじゃないかと思ったが……","ENG":"You were supposed to make the demonstration all fancy, but you finished it in 20 seconds. I was sure you'd be getting a mouthful for that...","TWN":"本來想讓你來一場精彩的近戰表演，結果戰鬥20秒就結束了，還以為她會抱怨幾句呢……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"다행히 좋게 봐주신 모양이더군.","JPN":"幸いにも高く評価してくださったようだ。","ENG":"But fortunately for you, I guess the top brass took kindly to your antics.","TWN":"幸好她似乎很滿意。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"넌 이제부터 델타세븐 내사과 소속의 카일 웡 대위가 되는 거야.","JPN":"君はこれからデルタセブン内偵課所属のカイル・ウォン大尉になるんだ。","ENG":"From now on, you'll be Captain Kyle Wong of the Internal Investigation Department of Delta Seven.","TWN":"從現在起，你就是第七三角洲部隊內務科的一員了，凱爾大尉。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그게 정말입니까?","JPN":"それは本当ですか？","ENG":"Could this really be true?","TWN":"真的嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"제가 델타세븐 소속......","JPN":"僕がデルタセブン所属……","ENG":"Me? Delta Seven?","TWN":"要我加入第七三角洲部隊……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"결재에 착오가 있을 지도 모릅니다.","JPN":"決裁に間違いがあったのかもしれません｡","ENG":"There may have been an error with the paperwork.","TWN":"說不定這個決策是錯誤的。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"만일을 대비해 당사자의 입장에서 진위 여부에 대한 사실확인 절차가 필요할 것 같습니다만.","JPN":"万が一のために、当事者の立場で真偽の程について事実確認の手続きが必要だと思いますが。","ENG":"Just to be safe, I think this may warrant a verification of the respective documentation by the parties affected.","TWN":"以防萬一，我必須以當事人的立場確認事情的真偽。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"나 참. 발령서 보여달란 얘기를 뭘 그렇게 어렵게 해?","JPN":"やれやれ。命令書を見たいという話をそんなに難しくするのか？","ENG":"Geez. That's a long-winded way to say you want to see your orders.","TWN":"真是的。命令書就這麼寫的，為什麼你要搞得這麼複雜？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"자, 여기. 실컷 읽어봐라.","JPN":"ほら、これだ。好きなだけ読んでみろ。","ENG":"Here you go. Read it all you'd like.","TWN":"來，就在這裡，自己好好看看吧。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이건 분명 국방부 직인이 찍힌 명령서...... 틀림없군요.","JPN":"これは確かに国防省の公印が押された命令書……間違いありませんね。","ENG":"This is indeed a personnel action order with the official stamp of the Department of Defense... There's no question about it.","TWN":"這確實是國防部蓋章的命令書……沒有問題。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"그래. 훈련병 주제에 대위 진급이라는 전례 없는 특혜다.","JPN":"そうだ。訓練兵から大尉への進級は、前例のない特別な措置だ。","ENG":"That's right. You're going from a trainee straight to Captain. I've never seen anyone get this kind of special treatment.","TWN":"對，一個訓練兵居然直接晉升為大尉，這可是特別待遇。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"그러니 트집 잡히기 싫으면 우쭐해 하지 말고 처신 잘 해야 할 거야.","JPN":"言いがかりをつけられなくなかったら、調子に乗らずに立ち振る舞いに気をつけろ。","ENG":"So you'd better carry yourself well. Don't get cocky, or others might look for a way to bring you down.","TWN":"如果你不想被抓到把柄就低調一點。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"뭐, 계급은 고사하고 델타세븐에 불려간다는 것 자체가 그리 좋은 일은 아닌 것 같다만......","JPN":"まぁ、階級はさておき、デルタセブンに異動になったこと自体があまり良くないことだろうが……","ENG":"Then again, I guess getting dragged to Delta Seven's not exactly something to celebrate...","TWN":"不過，先不說什麼晉升的事，光是被第七三角洲部隊叫過去就肯定不是什麼好事……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"교관 중위. 말하는 중에 미안하지만, 여긴 군대입니다. 상관인 제게 하대는 지양해주시죠.","JPN":"教官中尉。お話し中すみませんが、ここは軍です。上官である僕をぞんざいに扱うことはご遠慮願います。","ENG":"Instructor Lieutenant. I'd hate to interrupt you, but this is the military. I advise you refrain from treating your superior like a subordinate.","TWN":"教官中尉。很抱歉打斷您，但這裡是軍隊。長官對下屬的命令是絕對的。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"야, 이 자식아. 너 아직 진급식도 안 했거든?","JPN":"おい、こら。まだ進級申告式もやってないぞ。","ENG":"Hey, you little brat. You haven't even had your promotion ceremony yet, alright?","TWN":"喂，你這傢伙，你知不知道你還沒參加晉升儀式？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"진급 신고는 의례적인 절차일 뿐입니다. 이 서류를 통해 이미 실효성이 발휘된 상태니까요.","JPN":"進級申告式は形式的手続きに過ぎません。この書類ですでに実効性が発揮された状態ですから。","ENG":"A ceremony is merely that. A ceremony. With this document, my new rank has already entered into force.","TWN":"晉升儀式不過是走走程序罷了。我收到這份文件的這一刻，命令就已經生效了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"예, 예, 진급 축하 드립니다. 카일 웡 대위님.","JPN":"はい、はい。進級、おめでとうございます。カイル・ウォン大尉。","ENG":"Sure, sure. Congratulations on your promotion, sir. Captain Kyle Wong.","TWN":"是，是，恭喜您晉升，凱爾大尉。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"고맙군요. 교관. 내가 떠난 뒤에도 계속 이곳에서 인재양성교육에 힘 쏟아주길 바랍니다.","JPN":"感謝します、教官。僕が去った後も引き続きここで人材養成教育にご尽力を願います。","ENG":"Thank you, Instructor. Even after my departure, I hope you'd continue to invest your best efforts to foster capable service members.","TWN":"謝謝，教官。我離開後，也請繼續在這裡努力培養優秀的人才。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"......잠깐이나마 네가 떠나서 아쉽다고 생각한 나 자신이 참 한심해지는걸.","JPN":"……少しの間だけ君がここを離れて寂しいと思ってた自分が情けないな。","ENG":"I feel like an idiot for thinking for even a moment that it would be sad to see you go.","TWN":"……我剛才竟然還稍微為你的離開感到惋惜，我真是個笨蛋。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"자기비하는 좋지 않은 습관입니다.","JPN":"自己卑下は悪い習慣です。","ENG":"Self-deprecation is not a healthy habit.","TWN":"妄自薄菲不是一個好習慣。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"저는 교관이 교육자로서 본분을 충분히 다 하고 있다고 생각하니, 부디 자신감을 가지시죠.","JPN":"僕は、教官が教育者としての本分を全うしていると思いますので、どうか自信を持ってください。","ENG":"I trust that you are duly meeting expectations as an educator. So please, have more confidence in yourself.","TWN":"我相信教官可以成為一名優秀的教育者，請您務必保持自信。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"예, 예, 대위님의 격려에 몸 둘 바를 모르겠군요.","JPN":"はい、はい。大尉の励ましのお言葉に、ただただ恐縮するばかりです。","ENG":"Thank you, sir. You are most gracious, oh good sir, yes sir.","TWN":"是，是，能受到大尉的稱讚我很榮幸。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"곧 떠나셔야 하니 돌아가서 짐이나 챙기시죠.","JPN":"そろそろ時間ですので、戻って荷造りでもしてください。","ENG":"Why don't you go pack your stuff now, since you'll have to leave soon... sir.","TWN":"您馬上就要走了吧，那得快點回去收拾行李才行。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NEXTHOUSE_NPC_NULL_NULL","text":{"KOREA":"어! 카일 형! 어디 가는 거야?","JPN":"あ！　カイル兄さん！　どこ行くの？","ENG":"Oh! Kyle! Where are you going?","TWN":"啊！凱爾哥！你要去哪裡啊？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다른 부대에 발령이 돼서 거처를 옮기게 됐어.","JPN":"他の部隊に編入されて、引っ越すことになったんだ。","ENG":"I've been assigned to another unit. I have to move to a different place of residence.","TWN":"我剛剛收到了其它部隊下達的命令，得搬到別的地方了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NEXTHOUSE_NPC_NULL_NULL","text":{"KOREA":"아쉽다! 이제 형도 못 보고, 형이 모은 카운터 카드들도 구경 못하겠네.","JPN":"残念！　もう兄さんに会えないし、兄さんが集めてたカウンターカードも見れなくなっちゃう。","ENG":"That's too bad! Now I won't get to see you and your Counter cards collection.","TWN":"好可惜喔！以後不但看不到凱爾哥，也看不到哥收集的那些制裁者卡片了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이건 이제 너한테 줄게.","JPN":"これは君にあげるよ。","ENG":"You can keep this.","TWN":"這以後就是你的了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NEXTHOUSE_NPC_NULL_NULL","text":{"KOREA":"우왓! 이건 형의 콜렉션 북! 몇 년 동안 모은 한정판 카드들이 잔뜩 들어있는데?","JPN":"うわっ！　これは兄さんのコレクションブック！　何年も集めてきた限定版カードもいっぱい入ってるけど？","ENG":"Whoa! This is your collection book! But you've been collecting these limited edition cards for years!","TWN":"哇！這是凱爾哥的收集冊！裡面有好多限定卡耶，哥你不是收集了好幾年嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NEXTHOUSE_NPC_NULL_NULL","text":{"KOREA":"정말 이렇게 줘버려도 괜찮은 거야?","JPN":"本当にもらっていいの？","ENG":"Are you sure you can just give them away like this?","TWN":"就這樣給我真的沒關係嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그래. 정식 부대원이 된 이상 불필요한 잡동사니는 활동에 방해될 뿐이니까.","JPN":"うん。正式隊員になった以上、不要な荷物は邪魔になるだけだから。","ENG":"Yes. Now that I've become an official member of the unit, extraneous accessories will only serve as distractions.","TWN":"沒關係。成為正式的部隊成員後，這些不必要的東西只會妨礙我的行動而已。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"버리는 것보단 그걸 소중히 여길 줄 아는 사람에게 주는 편이 효율적이겠지.","JPN":"捨てるよりはこのカードの大切さを知っている人にあげたほうが効率的だろう。","ENG":"It'd be much more efficient to give it to someone who recognizes its value, rather than simply discarding it.","TWN":"與其扔掉它們，還不如送給一個真正愛惜它們的人。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......그럼 잘 지내라.","JPN":"……それじゃ、元気でね。","ENG":"Take care then.","TWN":"……那保重吧。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NEXTHOUSE_NPC_NULL_NULL","text":{"KOREA":"자, 잠깐만!","JPN":"ま、待って！","ENG":"W-wait!","TWN":"等，等一下！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NEXTHOUSE_NPC_NULL_NULL","text":{"KOREA":"그래도 이 카드는 가져가야지. 형이 제일 아끼던 거잖아.","JPN":"このカードだけは持って行きなよ。兄さんが一番大事にしてたものでしょ？","ENG":"You should take this card at least. This was your favorite.","TWN":"這張卡片哥你還是帶走吧，這不是哥最喜歡的一張嘛。"},"stage":{"bg":"KYLECC_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NEXTHOUSE_NPC_NULL_NULL","text":{"KOREA":"이제 수집은 안 하더라도, 전부 두고 갈 필요까진 없잖아?","JPN":"これ以上集めないかもしれないけど、全部置いていく必要はないんじゃないかな？","ENG":"Even if you don't collect them anymore, that doesn't mean you have to leave them all behind, right?","TWN":"就算不收集卡牌了，也沒必要全部留給我吧？"},"stage":{"bg":"KYLECC_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NEXTHOUSE_NPC_NULL_NULL","text":{"KOREA":"추억할 거리가 있다는 건 좋은 거라고 엄마가 그랬어.","JPN":"思い出の品があるのっていいことだってママが言ってた。","ENG":"Mom said it's good to have something to remember.","TWN":"我媽曾經告訴我，有值得回憶的東西是件好事。"},"stage":{"bg":"KYLECC_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그래, 고마워.","JPN":"わかった、ありがとう。","ENG":"Sure. Thanks.","TWN":"是嗎，謝謝你。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"여, 네가 신입이구나?","JPN":"やあ、君が新人か？","ENG":"Hey, you're the FNG, huh?","TWN":"嗨，你就是新人啊？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"예, 오늘 부로 델타세븐 내사과로 발령받게 된 카일 웡 대위입니다.","JPN":"はい、本日をもってデルタセブン内偵課に異動を命じられました、カイル・ウォン大尉です。","ENG":"Yes, sir. I'm Captain Kyle Wong, reporting for duty at the Delta Seven Internal Investigation Department as of today.","TWN":"是的，我是今天正式加入第七三角洲部隊內務科的凱爾大尉。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"함께 하게 되어 영광입니다.","JPN":"ご一緒できて光栄です。","ENG":"It's an honor to be working with you.","TWN":"很高興能與您一起工作。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그래, 내 이름은 제이크야. 편하게 형이라 불러.","JPN":"そうか。俺の名前はジェイクだ。気楽に兄さんって呼んでいいぞ。","ENG":"Sure. My name's Jake Walker. Feel free to call me by my first name.","TWN":"喔，我叫傑克，你就放輕鬆點，叫我傑克哥吧。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"어서 가자고. 사령관님께서 기다리고 계시니까.","JPN":"さあ、早く行こう。司令官がお待ちだ。","ENG":"Let's get going then. The Commander's waiting.","TWN":"我們快走吧。司令官正等著呢。"},"stage":{"bg":"HELI_NIGHT","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};